"use client"

import { useState, useEffect, useCallback, useRef } from "react"
import Image from "next/image"
import Link from "next/link"
import {
  getWebtoonSeriesList,
  saveWebtoonSeries,
  deleteWebtoonSeries,
  hydrateStore,
  WebtoonSeries,
  generateId,
} from "@/lib/store"
import { useAdmin } from "@/lib/admin-context"
import { AdminLoginDialog } from "@/components/admin-login-dialog"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Plus, Upload, Trash2 } from "lucide-react"

export default function WebtoonPage() {
  const { isAdmin } = useAdmin()
  const [seriesList, setSeriesList] = useState<WebtoonSeries[]>([])
  const [dialogOpen, setDialogOpen] = useState(false)
  const [title, setTitle] = useState("")
  const [description, setDescription] = useState("")
  const [thumbnail, setThumbnail] = useState("")
  const [mounted, setMounted] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    setMounted(true)
  }, [])

  const loadSeries = useCallback(async () => {
    await hydrateStore()
    setSeriesList(getWebtoonSeriesList())
  }, [])

  useEffect(() => {
    void loadSeries()
  }, [loadSeries])

  const handleThumbnailUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    const reader = new FileReader()
    reader.onload = () => {
      setThumbnail(reader.result as string)
    }
    reader.readAsDataURL(file)
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim() || !thumbnail) return

    const series: WebtoonSeries = {
      id: generateId(),
      title: title.trim(),
      description: description.trim(),
      thumbnail,
      createdAt: new Date().toISOString(),
    }

    saveWebtoonSeries(series)
    loadSeries()
    resetForm()
    setDialogOpen(false)
  }

  const handleDelete = (id: string) => {
    if (confirm("이 웹툰 시리즈를 삭제하시겠습니까? 모든 에피소드도 함께 삭제됩니다.")) {
      deleteWebtoonSeries(id)
      loadSeries()
    }
  }

  const resetForm = () => {
    setTitle("")
    setDescription("")
    setThumbnail("")
    if (fileInputRef.current) {
      fileInputRef.current.value = ""
    }
  }

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-foreground">웹툰</h1>
          <p className="mt-1 text-muted-foreground">
            연재 중인 웹툰 시리즈를 감상하세요
          </p>
        </div>
        {mounted && (
          isAdmin ? (
            <Dialog open={dialogOpen} onOpenChange={(o) => { setDialogOpen(o); if (!o) resetForm() }}>
              <DialogTrigger asChild>
                <Button className="gap-2">
                  <Plus className="w-4 h-4" />
                  새 시리즈 추가
                </Button>
              </DialogTrigger>
              <DialogContent className="sm:max-w-md" aria-describedby={undefined}>
                <DialogHeader>
                  <DialogTitle>새 웹툰 시리즈</DialogTitle>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-sm font-medium">시리즈 제목</label>
                    <Input
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="웹툰 제목을 입력하세요"
                      required
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">설명</label>
                    <Textarea
                      value={description}
                      onChange={(e) => setDescription(e.target.value)}
                      placeholder="웹툰 설명을 입력하세요"
                      rows={3}
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium">썸네일 이미지</label>
                    {thumbnail ? (
                      <div className="relative aspect-[3/4] w-full max-w-[200px] rounded-lg overflow-hidden bg-muted">
                        <Image
                          src={thumbnail}
                          alt="썸네일 미리보기"
                          fill
                          className="object-cover"
                        />
                        <Button
                          type="button"
                          variant="destructive"
                          size="sm"
                          className="absolute top-2 right-2"
                          onClick={() => setThumbnail("")}
                        >
                          삭제
                        </Button>
                      </div>
                    ) : (
                      <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        className="aspect-[3/4] w-full max-w-[200px] rounded-lg border-2 border-dashed border-border hover:border-primary flex flex-col items-center justify-center gap-2 transition-colors"
                      >
                        <Upload className="w-8 h-8 text-muted-foreground" />
                        <span className="text-sm text-muted-foreground">썸네일 업로드</span>
                      </button>
                    )}
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      onChange={handleThumbnailUpload}
                      className="hidden"
                    />
                  </div>

                  <div className="flex justify-end gap-2 pt-4">
                    <Button type="button" variant="ghost" onClick={() => setDialogOpen(false)}>
                      취소
                    </Button>
                    <Button type="submit" disabled={!title.trim() || !thumbnail}>
                      생성하기
                    </Button>
                  </div>
                </form>
              </DialogContent>
            </Dialog>
          ) : (
            <AdminLoginDialog><span /></AdminLoginDialog>
          )
        )}
      </div>

      {/* Series Grid */}
      {seriesList.length === 0 ? (
        <div className="text-center py-16">
          <p className="text-muted-foreground">아직 등록된 웹툰이 없습니다</p>
        </div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {seriesList.map((series) => (
            <div key={series.id} className="group relative">
              <Link href={`/webtoon/${series.id}`}>
                <div className="relative aspect-[3/4] rounded-lg overflow-hidden bg-muted shadow-md hover:shadow-lg transition-shadow">
                  <Image
                    src={series.thumbnail}
                    alt={series.title}
                    fill
                    className="object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                  <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-foreground/80 to-transparent p-3">
                    <h3 className="text-background font-medium text-sm line-clamp-2">
                      {series.title}
                    </h3>
                  </div>
                </div>
              </Link>
              {isAdmin && (
                <Button
                  variant="destructive"
                  size="icon"
                  className="absolute top-2 right-2 w-7 h-7 opacity-0 group-hover:opacity-100 transition-opacity"
                  onClick={() => handleDelete(series.id)}
                >
                  <Trash2 className="w-3 h-3" />
                </Button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}
